import { G, T, A, O, P } from './domains.js';

export const part7 = [
  {id:757,domain:A,question:"What is the purpose of network access control (NAC)?",options:["Enforces device compliance checks before granting network access","Physical entry control for equipment rooms","Limiting the number of admin accounts","Throttling bandwidth per department"],answer:0,explanation:"NAC solutions (Cisco ISE, Aruba ClearPass) check device posture (OS patch level, antivirus status, domain membership) before granting network access — non-compliant devices get placed in a quarantine VLAN with remediation access only, preventing unpatched/infected devices from reaching production networks.",optionExplanations:["NAC checks patch level and AV status, quarantining non-compliant devices before granting access.","This describes physical building access control, not network admission control.","Limiting admin accounts is access management, distinct from device posture checking.","Bandwidth throttling is a QoS function, unrelated to compliance-based network access."]},
  {id:758,domain:O,question:"What is a security information event management (SIEM) use case?",options:["A support-ticket response-time contract tier","A rule detecting a specific attack pattern","A licensing tier for log storage volume","Required server hardware specifications"],answer:1,explanation:"Example use cases: 'Impossible Travel' (same user logs in from US then China within an hour), 'Brute Force Detection' (5+ failed logins in 5 minutes), 'Privilege Escalation' (standard user added to Domain Admins) — each use case translates a known attack pattern into correlation rules and alerts.",optionExplanations:["Support response times are an SLA term, not a detection concept.","Use cases codify known attack patterns like impossible travel into correlation rules.","Storage licensing is a billing detail, not a detection logic concept.","Hardware specs are an infrastructure concern, unrelated to detection logic."]},
  {id:759,domain:T,question:"What is a session fixation attack?",options:["Restoring a crashed user session manually","DoS against session-token issuing servers","Fixing a session ID to hijack it later","Fixing bugs in session-management code"],answer:2,explanation:"If an application doesn't regenerate session IDs after login, an attacker can send a victim a link with a pre-set session ID (?PHPSESSID=attackerknown123) — once the victim logs in, the attacker uses that same session ID to access the authenticated session.",optionExplanations:["Restoring a crashed session is a support task, not an exploitation technique.","Session fixation is a hijacking technique, not an availability attack.","The attacker sets a known session ID, then hijacks it once the victim logs in.","Routine bug fixing is maintenance, not the attack technique itself."]},
  {id:760,domain:P,question:"What is the role of a Chief Information Security Officer (CISO)?",options:["The engineer writing all security code","Sets strategy and manages risk","A facilities manager for physical locks","A helpdesk staffer resolving IT tickets"],answer:1,explanation:"The CISO bridges the gap between technical security operations and executive/board-level business strategy — translating technical risk into business risk language, securing budget, and ensuring security supports rather than hinders business objectives.",optionExplanations:["CISOs set strategy at the executive level; they don't personally write all code.","The CISO establishes vision, strategy, and risk management aligned with business goals.","Physical security is one component, but the CISO oversees the entire program.","Helpdesk work is operational support, far below executive strategic responsibility."]},
  {id:761,domain:A,question:"What is the function of a reverse proxy?",options:["Forwards client requests, providing load balancing and SSL termination","Used only by internal staff for outbound browsing","A theoretical backward-routing proxy concept","Only decrypts traffic into plaintext"],answer:0,explanation:"Reverse proxies (NGINX, HAProxy) hide backend server details from clients, distribute load across multiple servers, cache static content, terminate SSL/TLS to offload encryption overhead, and can filter malicious requests (WAF functionality) before they reach application servers.",optionExplanations:["Reverse proxies centralize load balancing, caching, and SSL termination in front of backend servers.","Forward proxies serve outbound client requests; reverse proxies serve inbound ones.","This is wordplay; 'reverse' refers to direction, not time-travel routing.","SSL termination is only one optional function among several a reverse proxy performs."]},
  {id:762,domain:T,question:"What is a brute force attack?",options:["Physically forcing a biometric lock sensor","Physically unplugging network cabling","Trying many password combinations","Battering down a server-room door"],answer:2,explanation:"Online brute force attacks against login forms are typically slow and noisy (triggering lockouts), while offline brute force against captured password hashes can attempt billions of combinations per second using GPU clusters — strong, unique passwords and proper hashing (bcrypt, Argon2) are the primary defenses.",optionExplanations:["This is a physical bypass technique, not computational credential guessing.","Unplugging cables is physical sabotage, unrelated to guessing credentials.","Brute force exhaustively tries combinations, relying on computational power rather than exploits.","This describes a physical break-in, not an algorithmic password-guessing method."]},
  {id:763,domain:O,question:"What is the purpose of a runbook in security operations?",options:["A manual uptime logbook","Documented response procedures","A weekly staff shift schedule","A quarterly budget expenditure ledger"],answer:1,explanation:"A phishing email runbook might specify: 1) Quarantine the email across all mailboxes, 2) Check if any users clicked the link, 3) Reset credentials for affected users, 4) Block the sender domain — having this codified means any analyst can respond consistently, and the steps can often be automated via SOAR platforms.",optionExplanations:["Manual uptime logging is a monitoring record, distinct from response procedures.","Runbooks standardize response steps for known incidents, often supporting automation.","Shift scheduling is a staffing document, unrelated to incident procedures.","A budget ledger is a finance record, unrelated to operational procedures."]},
  {id:764,domain:A,question:"What is the principle behind a screened subnet (formerly DMZ) architecture?",options:["Isolates public-facing services","Filtering visual content on monitor screens","A reserved disaster-recovery failover segment","A subnet for video-conference displays"],answer:0,explanation:"Web servers, mail servers, and DNS servers in a screened subnet are reachable from the internet but have restricted access to internal networks — if a public-facing server is compromised, the attacker still must breach another firewall layer to reach internal systems, limiting blast radius.",optionExplanations:["Public servers sit here, reachable from the internet but restricted from internal systems.","This is wordplay about visual screens, not network traffic filtering.","DR subnets serve failover continuity, a different concern from perimeter segmentation.","This is unrelated to video-conferencing hardware; it's a security architecture zone."]},
  {id:765,domain:T,question:"What is a man-in-the-browser (MITB) attack?",options:["Corrupting saved bookmarks and history","Cross-browser rendering QA testing","Requiring physical presence at the desk","Trojan intercepting and altering transactions inside the browser"],answer:3,explanation:"MITB malware (like the Zeus banking trojan) injects malicious code into the browser process itself, allowing it to modify transaction details (e.g., changing the destination account number) after the user enters and confirms data but before it's transmitted — defeating even TLS encryption since the manipulation happens at the application layer inside the browser.",optionExplanations:["Bookmark corruption is unrelated; MITB targets live transaction content instead.","This isn't a QA testing technique; it's malicious browser exploitation.","MITB malware operates remotely and doesn't require physical presence at all.","MITB malware modifies transaction data inside the browser, defeating even TLS encryption."]},
  {id:766,domain:G,question:"What is the purpose of input validation in secure coding?",options:["Checking one name field only","Aesthetic form layout and color scheme","Counting the number of input fields","Sanitizing user input format"],answer:3,explanation:"Proper input validation (allowlisting expected characters/formats rather than blocklisting known-bad patterns) is the first line of defense against SQL injection, XSS, command injection, and buffer overflows — it should be performed server-side since client-side validation can be bypassed.",optionExplanations:["Input validation applies broadly to all untrusted data, not just one field.","Visual form design is a UX concern, unrelated to security validation.","Counting fields is a layout concern, unrelated to validating their content.","Validation checks data format, type, length, and range before processing to prevent injection attacks."]},
  {id:767,domain:O,question:"What is the purpose of vulnerability scanning frequency requirements in compliance frameworks?",options:["Left entirely to organizational discretion","Required only once, ever","Only once per year at most","Regular scans required by PCI DSS"],answer:3,explanation:"PCI DSS requires quarterly external vulnerability scans by an Approved Scanning Vendor (ASV) plus scans after any significant network change — this regular cadence catches newly disclosed CVEs and configuration drift that a one-time assessment would miss.",optionExplanations:["Frameworks like PCI DSS mandate concrete minimum frequencies, not open discretion.","A one-time scan quickly becomes outdated as new vulnerabilities emerge.","Annual-only scanning leaves long gaps where new vulnerabilities go undetected.","PCI DSS requires quarterly scans plus scans after significant network changes."]},
  {id:768,domain:T,question:"What is a clickjacking attack?",options:["Physical theft of computer mice","Legitimate ad click-through tracking","Tricking users into clicking a hidden overlay","Permanently disabling mouse and keyboard input"],answer:2,explanation:"An attacker overlays an invisible iframe of a legitimate page (e.g., a 'delete my account' or 'transfer funds' button) on top of an enticing decoy page — the user thinks they're clicking the decoy but actually clicks the hidden legitimate control, performing an unintended action.",optionExplanations:["This describes physical hardware theft, not the UI manipulation clickjacking involves.","Ad click tracking is legitimate analytics, unrelated to this deception technique.","An invisible overlay tricks users into clicking a hidden legitimate control.","This describes disabling input devices, not redirecting legitimate clicks."]},
  {id:769,domain:A,question:"What is the purpose of a Trusted Platform Module (TPM)?",options:["A vetted software-vendor procurement list","A synced cloud password manager app","Real-time network traffic trust monitor","Hardware chip generating and storing cryptographic keys for secure boot"],answer:3,explanation:"TPM chips store the encryption keys used by BitLocker/FileVault in hardware isolated from the OS, perform secure boot integrity measurements (detecting bootkit/rootkit tampering), and resist extraction even with physical access — Windows 11 requires TPM 2.0 partly for this hardware-rooted security.",optionExplanations:["A vendor allowlist is unrelated to TPM's cryptographic hardware role.","TPM is a hardware chip, not a software password manager.","Network traffic monitoring is a distinct function from TPM's key management role.","TPM securely generates and stores keys, enabling secure boot and disk encryption."]},
  {id:770,domain:P,question:"What is the purpose of a security control matrix or crosswalk?",options:["Maps controls across frameworks","A SOC wall dashboard display","A network topology diagram","An HR performance-review spreadsheet"],answer:0,explanation:"Organizations subject to multiple frameworks (e.g., a healthcare company needing HIPAA and PCI DSS compliance) use crosswalks to identify where a single implemented control satisfies requirements across frameworks, avoiding duplicate work and demonstrating comprehensive compliance efficiently.",optionExplanations:["Crosswalks show equivalencies between frameworks, avoiding duplicate compliance work.","This describes a physical SOC display, not a compliance mapping document.","A topology diagram shows infrastructure layout, a different artifact entirely.","Performance reviews are an HR function, unrelated to compliance mapping."]},
  {id:771,domain:T,question:"What is a fileless malware attack?",options:["Deleting every file on the disk","Executes in memory using PowerShell","Targeting files stored in cloud platforms","Malware requiring almost no disk space"],answer:1,explanation:"Fileless malware leverages 'living off the land' techniques — using PowerShell, WMI, or registry-based persistence — to execute malicious code entirely in memory, evading signature-based AV that scans files on disk, and often disappearing after a reboot, complicating forensic analysis.",optionExplanations:["Fileless malware doesn't necessarily delete files; it describes its execution method.","It abuses legitimate tools like PowerShell or WMI to run entirely in memory.","Cloud storage targeting is a different attack category from in-memory execution.","Fileless doesn't mean minimal size; it means avoiding executable files entirely."]},
  {id:772,domain:O,question:"What is the purpose of a Security Orchestration, Automation, and Response (SOAR) platform?",options:["Physical guard-shift scheduling platform","Ambient music system for SOC stress","Automates security response playbooks","A dedicated vulnerability-scan scheduler"],answer:2,explanation:"SOAR platforms (Splunk SOAR, Palo Alto XSOAR) connect to SIEM, EDR, firewalls, and ticketing systems, executing automated playbooks (e.g., automatically isolating an infected host, blocking a malicious IP across all firewalls, and opening a ticket) in seconds rather than the minutes/hours manual response would take.",optionExplanations:["This describes physical guard scheduling, not SOAR's technical automation role.","This is wordplay; SOAR has nothing to do with music.","SOAR integrates tools and automates repetitive response tasks via playbooks.","Vulnerability scanning is only one possible integration, not SOAR's core function."]},
  {id:773,domain:A,question:"What is the difference between full disk encryption (FDE) and file-level encryption?",options:["Only works on solid-state drives","Encrypts an entire volume versus individual selected files","File-level is always faster than FDE","No meaningful difference between the two"],answer:1,explanation:"FDE (BitLocker, FileVault) protects data at rest if a device is lost/stolen since the entire drive is unreadable without the decryption key, but offers no protection once the OS is running and the user is authenticated — file-level encryption can keep specific sensitive files protected even from other authenticated users on the same system.",optionExplanations:["FDE works on both HDDs and SSDs, not exclusively solid-state drives.","FDE protects the whole volume at rest; file-level encryption protects specific files.","Performance varies by implementation; hardware-accelerated FDE can outperform software file encryption.","These are distinct approaches with different security properties and use cases."]},
  {id:774,domain:T,question:"What is a credential stuffing attack?",options:["Automated reuse of breached login credentials","Overflowing a login form's input buffer","Physically overloading authentication server power","Submitting fake credentials to distract defenders"],answer:0,explanation:"Because many users reuse passwords across services, attackers take credentials leaked in one breach (e.g., a gaming site) and test them en masse against unrelated high-value targets (banking, email) using automated tools — MFA and breached-password screening (checking against Have I Been Pwned-style databases) are key defenses.",optionExplanations:["Attackers reuse credentials leaked in one breach against other unrelated services.","This isn't about buffer overflow; it's automated credential reuse testing.","This describes physical power overload, not an automated login attack.","This is a real automated attack attempting genuine logins, not a distraction."]},
  {id:775,domain:G,question:"What is the purpose of separation of duties as a security control?",options:["Relocating staff to separate buildings","Dividing tasks so no one person acts alone","Grouping staff by preferred programming language","Staggering lunch breaks for project teams"],answer:1,explanation:"Example: the person who requests a wire transfer cannot also approve it, and the person who approves it cannot also execute it — this requires collusion between multiple people to commit fraud, significantly raising the difficulty and detection likelihood compared to a single insider acting alone.",optionExplanations:["Physical relocation isn't the mechanism; it's about dividing process responsibilities.","Separation of duties requires multiple people to collude to commit fraud.","Programming language preference is irrelevant to this security control.","Lunch scheduling is unrelated to dividing sensitive process responsibilities."]},
  {id:776,domain:O,question:"What is a security baseline configuration?",options:["The lowest approved security budget level","Average bandwidth utilization measurement","A single default password at setup","Minimum config used to detect drift"],answer:3,explanation:"Security baselines (CIS Benchmarks, DISA STIGs) define settings like disabled unnecessary services, required password policies, and audit logging configuration — automated tools (SCAP scanners) regularly check deployed systems against the baseline, flagging any drift for remediation.",optionExplanations:["Budget is a financial concept, unrelated to technical configuration standards.","Bandwidth measurement is performance monitoring, a different concept from baselines.","Default passwords are one setting among many; baselines define the full state.","Baselines define the expected secure configuration, enabling automated drift detection."]},
  {id:777,domain:T,question:"What is an evil twin attack?",options:["Two coordinated attackers working together","An attack on backup data centers","Self-replicating malware duplicating itself","A rogue AP mimicking a legitimate SSID to intercept traffic"],answer:3,explanation:"An attacker sets up an AP broadcasting the same SSID as a legitimate network (e.g., 'Airport_WiFi') often with a stronger signal — victims' devices auto-connect to the familiar name, allowing the attacker to perform MITM attacks, capture credentials, or serve malicious content.",optionExplanations:["'Evil twin' refers to a rogue access point, not coordinated human attackers.","This targets wireless clients, not redundant data center infrastructure.","This is a wireless network attack, not malware self-replication.","Devices auto-connect to the familiar SSID, letting the attacker intercept traffic."]},
  {id:778,domain:A,question:"What is the purpose of micro-segmentation in a data center network?",options:["Consolidating servers to reduce hardware","Replacing cabling with thinner cables","Splitting a campus into separate buildings","Granular per-workload policy zones"],answer:3,explanation:"Unlike traditional VLAN segmentation which creates broad zones, micro-segmentation (using tools like VMware NSX or Illumio) can restrict communication down to the individual VM/container level — even systems on the same subnet must have explicit policy permission to communicate, dramatically limiting lateral movement if one workload is compromised.",optionExplanations:["Server consolidation is an efficiency concern, unrelated to micro-segmentation's purpose.","Cable size is a physical layer concern, unrelated to logical segmentation.","Physical building division is impractical; micro-segmentation is software-defined.","Micro-segmentation restricts communication down to the individual workload, supporting zero trust."]},
  {id:779,domain:O,question:"What is the purpose of a post-incident review (lessons learned) meeting?",options:["Immediately closing the incident ticket","A celebratory team gathering","Formally assigning blame to one person","Analysis to prevent recurrence"],answer:3,explanation:"Effective lessons-learned meetings follow a blameless post-mortem approach, focusing on systemic and process improvements (e.g., 'why did detection take 6 hours?' leads to better alerting) rather than individual blame, which encourages honest disclosure of mistakes that improves future response.",optionExplanations:["Skipping analysis forfeits the value of the incident as a learning opportunity.","Team recognition can be positive, but analysis is the primary purpose.","Blameless reviews are recommended since blame culture suppresses honest reporting.","A structured review analyzes what happened and identifies improvements for the future."]},
  {id:780,domain:T,question:"What is the purpose of a logic bomb?",options:["Dormant code triggered by a specific condition","Physical explosives destroying network hardware","A brute-force password-cracking tool","An anonymous recorded bomb threat call"],answer:0,explanation:"A classic example: a disgruntled employee plants code that deletes critical database tables if their employee ID is removed from the payroll system (indicating termination) — logic bombs are particularly dangerous insider threats because they can remain undetected for long periods before triggering.",optionExplanations:["Logic bombs lie dormant until a trigger condition, often planted by insiders.","Logic bombs are software attacks, not physical hardware destruction.","This isn't password cracking; it's a conditionally triggered malicious payload.","This is a physical threat/communication, not a software attack technique."]},
  {id:781,domain:G,question:"What is the purpose of a security awareness training program?",options:["A single onboarding-only training session","Annual fire-safety evacuation training","Ongoing education reducing human-factor breach risk through phishing training","Training limited to the IT security team"],answer:2,explanation:"Since human error and social engineering are involved in the majority of breaches, ongoing security awareness training (phishing simulations, periodic refreshers, role-based training) is one of the highest-ROI security investments — a single onboarding session is quickly forgotten without reinforcement.",optionExplanations:["One-time onboarding training has limited long-term retention without reinforcement.","Fire safety is physical safety training, a separate topic from cybersecurity.","Ongoing training directly addresses the human element, one of the most exploited vectors.","Awareness training targets all employees, since everyone is a potential target."]},
  {id:782,domain:O,question:"What is the purpose of a digital forensic disk image (bit-for-bit copy)?",options:["A photograph of the drive casing","A backup of only active visible files","Exact sector-by-sector duplicate","A brief disk-usage summary report"],answer:2,explanation:"Forensic imaging tools (FTK Imager, dd) create a verified (hash-matched) bit-for-bit copy so investigators can analyze a working copy while the original remains pristine and unaltered — write blockers are used during imaging to prevent any modification to the source device, preserving evidentiary integrity.",optionExplanations:["This isn't a literal photograph; it's a data-level exact duplication.","Active-file-only backups miss deleted data and forensic artifacts.","Bit-for-bit imaging captures deleted data and unallocated space, preserving evidentiary integrity.","A usage summary lacks the actual data needed for forensic examination."]},
  {id:783,domain:T,question:"What is an XML External Entity (XXE) injection attack?",options:["Exploiting XML parser flaws for SSRF","Converting XML configs into corrupted JSON","Injecting malformed XML to crash the parser","Targeting XML-based router routing protocols"],answer:0,explanation:"Vulnerable XML parsers that process DOCTYPE declarations with external entities can be exploited with payloads like <!ENTITY xxe SYSTEM 'file:///etc/passwd'> to read arbitrary local files, or to make the server perform SSRF requests to internal systems — disabling external entity processing in the parser is the primary defense.",optionExplanations:["Vulnerable parsers process external entity references, allowing file disclosure or SSRF requests.","Format conversion is unrelated; XXE exploits parsing behavior, not data transformation.","This isn't about formatting errors; it's malicious entity resolution.","This is an application-layer flaw in XML parsing, not a routing protocol attack."]},
  {id:784,domain:A,question:"What is the function of an Intrusion Prevention System (IPS) compared to an IDS?",options:["IDS is always more accurate","IPS is wireless-only, IDS is wired-only","Just two names for the same tech","IPS blocks inline; IDS only alerts"],answer:3,explanation:"IDS is deployed out-of-band (monitoring a copy of traffic via a SPAN/mirror port), so it can alert but not block in real time, while IPS is deployed inline (directly in the traffic path), allowing it to drop malicious packets immediately — the tradeoff is that IPS false positives can disrupt legitimate traffic, while IDS false positives are just noisy alerts.",optionExplanations:["Accuracy depends on tuning, not which deployment mode is used.","Both can be deployed on wired or wireless networks.","IDS and IPS differ in deployment mode and response capability.","IPS sits inline to actively block traffic, while IDS passively alerts only."]},
  {id:785,domain:P,question:"What is the purpose of a data retention policy?",options:["Mandatory daily backup to secondary storage","Defines how long data is kept and when it's destroyed","Restricting who can create new records","Ensuring no data is ever deleted"],answer:1,explanation:"Data retention policies specify, for example, that financial records must be kept 7 years (tax requirements) while old marketing emails can be deleted after 90 days — minimizing unnecessarily retained data reduces breach impact (less data to steal) and reduces storage/compliance costs, while still meeting legal hold requirements.",optionExplanations:["Backup frequency is an availability concern, distinct from retention length.","Retention policies balance legal requirements, business needs, and breach-impact risk.","Retention governs data lifecycle and destruction, not creation access.","Retention policies specifically define when data should be deleted, not indefinite storage."]},
  {id:786,domain:T,question:"What is a race condition vulnerability?",options:["Attackers racing to crack a password first","A flaw exclusive to racing video games","Timing-dependent flaw exploited via TOCTOU","A system processing requests unusually fast"],answer:2,explanation:"TOCTOU race conditions occur when a security check (e.g., verifying file permissions) and the actual use of that resource happen at different times — an attacker can swap the resource between the check and use (e.g., replacing a validated file with a malicious symlink) to bypass the security control.",optionExplanations:["This isn't about competing with lockout timers; it's exploiting timing gaps.","This is a general software flaw, not specific to gaming applications.","Race conditions exploit the gap between checking and using a resource.","Race conditions concern timing vulnerabilities, not literal execution speed."]},
  {id:787,domain:O,question:"What is a key performance indicator (KPI) used to measure SOC effectiveness?",options:["Total company headcount","Number of firewall appliances deployed","Mean Time to Detect and Respond","Number of analyst coffee breaks"],answer:2,explanation:"MTTD (time from compromise to detection) and MTTR (time from detection to containment/resolution) are industry-standard SOC metrics — reducing these numbers through better tooling, automation, and process directly correlates with reduced breach impact and cost, since dwell time strongly influences damage extent.",optionExplanations:["Headcount is unrelated to demonstrating detection and response capability.","Firewall count is an inventory metric, not an effectiveness measure.","MTTD and MTTR directly measure the speed of detection and response.","This is unrelated to operational security performance measurement."]},
  {id:788,domain:T,question:"What is a supply chain attack in the context of software development?",options:["Targeting hardware in physical shipping","Compromising a trusted vendor's software","Halting a factory assembly line","Targeting freight and logistics warehouses"],answer:1,explanation:"The SolarWinds attack compromised the build pipeline to insert malicious code into legitimate signed software updates, which were then trusted and installed by thousands of organizations — supply chain attacks are particularly dangerous because they exploit the inherent trust relationship between software vendors and their customers.",optionExplanations:["Supply chain attacks span both hardware and software, not just physical shipping.","A compromised upstream vendor or library affects every downstream consumer that trusts it.","This isn't about physical manufacturing; it concerns software distribution.","This refers to the software delivery pipeline, not physical logistics."]},
  {id:789,domain:A,question:"What is the purpose of DNS Security Extensions (DNSSEC)?",options:["Speeding up DNS query resolution","Encrypting all DNS query contents","A full replacement for DNS","Cryptographic signatures verifying DNS record authenticity against spoofing"],answer:3,explanation:"DNSSEC uses a chain of trust with digital signatures (RRSIG records) from the root zone down to individual domains, allowing validating resolvers to cryptographically verify that a DNS response genuinely came from the authoritative source and wasn't altered in transit — note DNSSEC provides integrity/authenticity, not confidentiality (DNS queries remain visible; that's addressed separately by DNS over HTTPS/TLS).",optionExplanations:["DNSSEC adds cryptographic overhead rather than speeding up resolution.","DNSSEC provides authenticity, not confidentiality; queries remain visible in plaintext.","DNSSEC extends existing DNS with security features, not a full replacement.","Digital signatures let resolvers verify DNS responses weren't altered or spoofed."]},
  {id:790,domain:G,question:"What is the difference between a vulnerability and an exploit?",options:["Vulnerability is software-only, exploit is hardware-only","A weakness versus the code that abuses it","An exploit is always more severe","The two terms are pure synonyms"],answer:1,explanation:"A vulnerability (e.g., an unpatched buffer overflow flaw, CVE-2024-XXXX) is the underlying weakness; the exploit is the working proof-of-concept or weaponized code that actually triggers and abuses that flaw to achieve a malicious outcome — a vulnerability can exist without a known exploit yet (theoretical risk) until someone develops one.",optionExplanations:["Both vulnerabilities and exploits can apply to software or hardware.","A vulnerability is the underlying flaw; the exploit is the code that abuses it.","Severity doesn't depend on the label; a vulnerability can be critical without an exploit.","These describe distinct but related concepts in the vulnerability lifecycle."]},
  {id:791,domain:O,question:"What is threat hunting?",options:["HR disciplinary action for policy violations","Researching new threat-intel vendor subscriptions","Physical guard patrols of server rooms","Proactively searching for missed threats"],answer:3,explanation:"Threat hunters form hypotheses (e.g., 'could an attacker be using PsExec for lateral movement undetected?') and proactively query logs, endpoint telemetry, and network data to test them, often uncovering sophisticated or long-dwelling threats that signature-based and rule-based detection missed entirely.",optionExplanations:["This isn't disciplinary action; it's searching for malicious actors technically.","This isn't vendor procurement; it's an active, analyst-driven detection method.","This is a cybersecurity analytical practice, not physical patrol activity.","Threat hunters proactively test hypotheses rather than waiting passively for alerts."]},
  {id:792,domain:T,question:"What is a privilege escalation attack?",options:["Gradually escalating network traffic volume","Exploiting a flaw to gain higher access","A standard HR promotion process","Justifying a growing annual security budget"],answer:1,explanation:"Vertical privilege escalation moves from a lower privilege level to a higher one (user to admin), often via unpatched kernel exploits or misconfigured services, while horizontal escalation accesses another user's resources at the same privilege level — both are critical steps attackers take after initial foothold to achieve their objectives.",optionExplanations:["This isn't a traffic-volume attack; it's about gaining elevated permissions.","Attackers exploit vulnerabilities or misconfigurations to move from limited to higher access.","This describes legitimate HR promotion, not unauthorized technical escalation.","Budget is a financial concept, unrelated to technical access escalation."]},
  {id:793,domain:A,question:"What is the purpose of redundant array of independent disks (RAID) in the context of availability?",options:["Combines disks for redundancy and performance to aid availability","A full replacement for backups","Used exclusively to encrypt stored data","Prevents all data loss including ransomware"],answer:0,explanation:"RAID 1 (mirroring) and RAID 5/6 (striping with parity) allow a system to continue operating and data to remain accessible even if one (or more, depending on RAID level) physical disk fails — but RAID is not a backup, since it doesn't protect against accidental deletion, ransomware encryption, or site-level disasters that backups and DR plans address.",optionExplanations:["RAID 1 mirroring and RAID 5/6 striping keep data accessible despite disk failure.","RAID isn't a backup substitute since it doesn't protect against deletion or ransomware.","RAID is unrelated to encryption; it's a redundancy and performance technology.","RAID mirrors ransomware encryption across all disks identically, offering no protection."]},
  {id:794,domain:T,question:"What is a directory traversal (path traversal) attack?",options:["Reaching restricted files via '../'","Physical office directory listings and maps","Manually scanning a printed phone book","Manipulating network routing table entries"],answer:0,explanation:"Example: a vulnerable file download feature accepting ?file=report.pdf could be exploited with ?file=../../../../etc/passwd to access files far outside the intended download directory — proper input validation, allowlisting, and running with least-privilege file system permissions are key defenses.",optionExplanations:["Weak input sanitization lets attackers use '../' sequences to escape the intended directory.","Path traversal is a digital exploit, not physical building navigation.","This isn't related to phone directories; it's a file-system vulnerability.","This targets a server's file system, not network routing infrastructure."]},
  {id:795,domain:P,question:"What is the purpose of a Statement of Work (SOW) in vendor security engagements?",options:["A generic boilerplate NDA template","Formal scope, deliverables, and terms","A vendor's revenue and profit statement","A vendor's marketing and satisfaction scores"],answer:1,explanation:"For a penetration test engagement, the SOW would specify exact systems in scope, testing methodology, deliverable format (report structure), timeline, and payment terms — providing a contractual basis for what work will be performed and preventing scope disputes after the engagement begins.",optionExplanations:["NDAs are a separate legal document focused on confidentiality, not scope.","The SOW defines exact scope, deliverables, timeline, and payment terms for the engagement.","Vendor financial information is unrelated to defining engagement scope.","Marketing claims aren't the purpose; an SOW is a binding scope document."]},
  {id:796,domain:T,question:"What is typosquatting?",options:["A flaw in mobile autocorrect engines","Registering misspelled domains","Compromising a domain registrar's systems","A fast-typing competition contest"],answer:1,explanation:"An attacker might register 'gooogle.com' or 'arnazon.com' to capture users who mistype the intended URL — visitors might be served phishing pages mimicking the legitimate site, malicious ads, or have the domain sold back to the legitimate company at inflated prices.",optionExplanations:["This isn't an autocorrect flaw; it's deliberate exploitation of typing mistakes.","Attackers register misspelled lookalike domains to capture users who mistype a URL.","This isn't an attack on registrars; it's misuse of legitimate registration services.","This isn't a recreational activity; it's a malicious domain registration technique."]},
  {id:797,domain:O,question:"What is the purpose of an after-action report following a security incident?",options:["A daily status update with no incident","Documentation solely for an insurance claim","Formal summary of timeline, response, and improvement recommendations","A payroll document of overtime hours"],answer:2,explanation:"After-action reports are more formal and comprehensive than lessons-learned meeting notes, often required for compliance/legal purposes and executive reporting — they document what happened, why, the response effectiveness, and concrete remediation action items with owners and deadlines.",optionExplanations:["AARs are retrospective documents produced after resolution, not routine daily updates.","Insurance claims may reference it, but its primary purpose is broader documentation.","AARs document what happened, why, and concrete remediation items for the future.","Overtime tracking is an HR/payroll concern, unrelated to incident documentation."]},
  {id:798,domain:A,question:"What is the purpose of an Application Programming Interface (API) gateway in security architecture?",options:["Translating code between languages","Enforces auth and rate limiting centrally","Archiving API documentation and specs","A physical turnstile for server-room entry"],answer:1,explanation:"API gateways (Kong, Apigee, AWS API Gateway) centralize cross-cutting security concerns — API key/OAuth token validation, rate limiting to prevent abuse, request/response transformation, and logging — so individual microservices don't each need to reimplement these controls, while also providing a single point for monitoring and threat detection across all API traffic.",optionExplanations:["API gateways manage traffic and policy, not language translation.","Gateways centralize authentication, rate limiting, and validation before requests reach backend services.","This is a documentation backup system, not an active traffic-management component.","This describes physical access control, unrelated to API traffic management."]},
  {id:799,domain:T,question:"What is a deauthentication attack against wireless networks?",options:["A legitimate scheduled client-management feature","Permanently jamming all radio frequencies","Targeting wired 802.1X switch ports","Spoofed frames to capture the WPA handshake"],answer:3,explanation:"Because 802.11 management frames were historically unauthenticated/unencrypted, an attacker can spoof deauth frames appearing to come from the AP, forcing a client to disconnect and reconnect — capturing the WPA/WPA2 4-way handshake during reconnection for offline password cracking, or as a denial-of-service/precursor to an evil twin attack. 802.11w (Protected Management Frames) mitigates this.",optionExplanations:["Legitimate deauth frames exist, but this attack uses spoofed frames maliciously.","Deauth attacks force temporary, targeted disconnection, not permanent jamming.","This targets 802.11 wireless management frames, not wired Ethernet authentication.","Spoofed deauth frames force reconnection, letting attackers capture the WPA handshake for cracking."]},
  {id:800,domain:G,question:"What is the purpose of the CIA triad in information security?",options:["Categories for classifying every cyberattack","Confidentiality, Integrity, and Availability","Three certifications professionals must earn","Reference to Central Intelligence Agency standards"],answer:1,explanation:"Confidentiality ensures data is only accessible to authorized parties (encryption, access control), Integrity ensures data hasn't been improperly altered (hashing, digital signatures), and Availability ensures systems/data are accessible when needed (redundancy, DDoS protection) — virtually every security control can be mapped to supporting one or more of these three objectives.",optionExplanations:["The triad describes goals to protect, not categories of attacks.","Confidentiality, Integrity, and Availability form the foundational security objectives model.","This isn't about certifications; it's a conceptual objectives framework.","This is a naming coincidence; the CIA triad is unrelated to the intelligence agency."]},
  {id:801,domain:O,question:"What is the purpose of network traffic baselining?",options:["A one-time hardware setup test","Profiling normal traffic to detect anomalies","A guaranteed minimum connection speed","A fixed maximum bandwidth cap"],answer:1,explanation:"Once a baseline is established (e.g., normal traffic to a specific server averages 50GB/day on HTTPS), anomaly detection tools can flag deviations like a sudden 500GB outbound transfer at 3 AM as suspicious — without a baseline, abnormal activity may blend into the noise of 'normal' unanalyzed traffic.",optionExplanations:["Baselining is ongoing, not a single initial test.","A baseline of normal traffic lets analysts spot deviations that signal a problem.","This describes an SLA guarantee, not traffic characterization.","Baselining characterizes typical behavior; it doesn't set a hard bandwidth ceiling."]},
  {id:802,domain:T,question:"What is a DNS tunneling attack?",options:["A DNS caching optimization that speeds up name resolution","Hiding data in DNS queries to evade firewalls","Physically tapping DNS fiber cables","Corrupting a DNS server's zone file"],answer:1,explanation:"Because DNS is essential for normal operation and often permitted outbound with limited inspection, attackers encode malware C2 commands or stolen data into DNS query subdomains (e.g., stolen-data-chunk1.attacker-domain.com) — DNS tunneling tools like Iodine or DNSCat2 can establish a covert communication channel that bypasses traditional firewall/proxy controls.",optionExplanations:["Tunneling adds overhead, so it is slower, not faster.","DNS tunneling smuggles data or C2 traffic inside DNS queries that firewalls rarely inspect.","This is a protocol-level technique, not physical cable tampering.","Tunneling hides data in queries; it doesn't corrupt stored zone records."]},
  {id:803,domain:A,question:"What is the purpose of a load balancer in availability architecture?",options:["A device used to physically weigh server rack hardware","Reducing the number of servers owned","Testing a server's maximum capacity","Distributing traffic across multiple servers"],answer:3,explanation:"Load balancers (F5, AWS ELB, NGINX) distribute traffic using algorithms like round-robin or least-connections, and perform health checks to automatically route traffic away from failed/unhealthy servers — this provides both performance benefits and availability resilience since the failure of one backend server doesn't cause an outage.",optionExplanations:["This is wordplay; load balancing concerns traffic, not physical weight.","Load balancers often need multiple servers, not fewer, to provide redundancy.","Load testing is a related but separate activity from ongoing traffic distribution.","Load balancers spread traffic and reroute around failed servers to avoid a single point of failure."]},
  {id:804,domain:O,question:"What is the purpose of conducting a business impact analysis (BIA)?",options:["Analyzing one unit's profitability","A one-time report summarizing a single penetration test's findings","An annual employee satisfaction survey","Assessing disruption impact to set RTOs and RPOs"],answer:3,explanation:"A BIA identifies critical business processes (e.g., order processing, payment systems), quantifies the impact of their disruption over time (financial loss, reputational damage, regulatory penalties), and uses this analysis to set RTO/RPO targets that then drive disaster recovery and business continuity planning priorities and budget allocation.",optionExplanations:["BIA considers continuity impact broadly, not just unit profit.","A BIA is a continuity process, not a technical security test.","Employee morale surveys are an HR function unrelated to continuity planning.","A BIA quantifies disruption impact and sets the RTO/RPO targets that drive recovery planning."]},
  {id:805,domain:T,question:"What is a SQL injection second-order attack?",options:["Targeting only the second database in a cluster","Stored input later triggering injection in another query","SQL injection occurring exactly twice","A fallback technique after a failed attempt"],answer:1,explanation:"Example: a user registers with a username containing SQL metacharacters that pass initial input validation (since it's just stored as a string), but later, when an admin panel queries 'SELECT * FROM logs WHERE user=' + storedUsername without parameterization, the injection executes — the delayed execution path makes second-order injection harder to detect with simple input testing.",optionExplanations:["This isn't about which server is targeted; it's about delayed execution.","Input stored safely at first later triggers injection when an unrelated query uses it unsafely.","'Second-order' refers to delayed execution, not a count of occurrences.","This is a distinct technique based on timing, not a fallback method."]},
  {id:806,domain:P,question:"What is the purpose of a privacy impact assessment (PIA)?",options:["An assessment done only after a breach","Calculating only the upfront cost of new privacy software","Evaluating a project's data risks before launch","A performance review of the privacy officer"],answer:2,explanation:"PIAs (required under GDPR as DPIAs for high-risk processing) are conducted proactively during system design — they identify what personal data will be collected, why, how it will be protected, and whether less privacy-invasive alternatives exist, embodying the privacy-by-design principle rather than retrofitting privacy after deployment.",optionExplanations:["PIAs are proactive, done before implementation, not reactive to a breach.","A PIA evaluates privacy risk broadly, not just software cost.","A PIA identifies data collection and privacy risks during design, embodying privacy by design.","This is a risk assessment of a system, not an employee evaluation."]},
  {id:807,domain:T,question:"What is an ARP cache poisoning attack?",options:["Corrupting a DNS resolver's cache","Clearing a browser's cached history","Physically damaging a network router's internal hardware","Spoofed ARP replies enabling a MITM attack"],answer:3,explanation:"Because ARP has no built-in authentication, an attacker can broadcast spoofed ARP replies claiming their MAC address corresponds to the gateway's IP — victim devices update their ARP cache and send traffic intended for the gateway to the attacker instead, who can then intercept, modify, or relay it (MITM) — Dynamic ARP Inspection (DAI) on switches is a key defense.",optionExplanations:["This targets DNS at a different layer than ARP poisoning.","This isn't about browser cache; ARP operates at the network layer.","ARP poisoning is a logical attack, not physical sabotage.","Falsified ARP replies bind the attacker's MAC to another host's IP, enabling interception."]},
  {id:808,domain:A,question:"What is the purpose of a content delivery network (CDN) from a security perspective?",options:["Distributed edge servers that absorb DDoS traffic","A private inter-office communications network","A specialized network built exclusively for streaming video","A network enforcing content licensing agreements"],answer:0,explanation:"CDNs like Cloudflare and Akamai distribute massive amounts of capacity globally, which can absorb volumetric DDoS attacks that would overwhelm a single origin server — many CDNs also offer integrated WAF and bot mitigation services at the edge, filtering malicious traffic before it ever reaches the origin infrastructure.",optionExplanations:["CDNs distribute massive capacity globally and offer edge WAF, absorbing large attacks before they reach the origin.","CDNs serve public content delivery, not internal-only communications.","CDNs deliver many content types, not exclusively video.","Licensing is a legal concern, separate from a CDN's delivery function."]},
  {id:809,domain:O,question:"What is the purpose of an incident severity classification system?",options:["Used only for after-the-fact compliance reports","Categorizing incidents by impact to guide response","Sorting incidents alphabetically by name","Classifying incidents by attacker nationality"],answer:1,explanation:"Severity classification (often based on factors like data sensitivity affected, system criticality, and scope) ensures a ransomware attack on the primary domain controller gets immediate all-hands response while a single isolated phishing email triggers standard, less urgent handling — without this triage, organizations risk either under-responding to critical incidents or wasting resources over-responding to minor ones.",optionExplanations:["Severity classification drives real-time response decisions, not just compliance paperwork.","Classifying by impact and urgency ensures critical incidents get immediate resources.","Alphabetical sorting has no bearing on incident priority.","Attacker attribution isn't a factor; impact and urgency are."]},
  {id:810,domain:T,question:"What is a watering hole versus spear phishing — what's the key distinguishing factor?",options:["Only targets government websites","No real difference between them","Direct email vs. a compromised site","Spear phishing is always less effective"],answer:2,explanation:"Spear phishing is an active, direct approach (crafting a convincing email to a specific person), while watering hole is a passive, indirect approach (compromising a site and waiting) — attackers may choose watering hole when direct targeting (email/social engineering) is difficult due to a hardened target who is unlikely to fall for direct phishing attempts.",optionExplanations:["Watering holes can target any site the victims frequent.","These are fundamentally different methodologies despite similar goals.","The key difference is direct outreach versus indirect, passive compromise-and-wait.","Effectiveness depends on context; neither is universally superior."]},
  {id:811,domain:G,question:"What is the principle of least functionality in system hardening?",options:["Reducing electricity consumption","Limiting how many concurrent users may access a system","Disabling unnecessary services and ports","Shrinking server rack dimensions"],answer:2,explanation:"A web server hardened with least functionality would have unnecessary services (FTP, Telnet, unused database engines) disabled, unused ports closed, and unneeded software uninstalled — every running service is a potential vulnerability and attack vector, so removing what isn't needed directly shrinks the attack surface.",optionExplanations:["This is about capability minimization, not power usage.","User limits are a capacity concern, not a hardening principle.","Every unneeded running service is a potential attack vector, so disabling them shrinks the attack surface.","Physical size is unrelated to service or software configuration."]},
  {id:812,domain:O,question:"What is the purpose of file integrity monitoring (FIM)?",options:["Tracking file download speeds","Alerting on unauthorized changes to critical files","Monitoring free disk space","Copying files to a secondary location for backup and recovery"],answer:1,explanation:"FIM tools (Tripwire, OSSEC) calculate cryptographic hashes of critical files (system binaries, configuration files like /etc/passwd) and alert when changes are detected — since malware and attackers often modify system files for persistence or to disable security controls, unexpected changes are a strong indicator of compromise.",optionExplanations:["Download speed is a performance metric, not integrity monitoring.","FIM hashes critical files and alerts when unexpected changes suggest tampering or compromise.","Disk capacity monitoring is a different operational concern.","Backup copies data; FIM detects unauthorized modification."]},
  {id:813,domain:T,question:"What is a downgrade attack in the context of cryptographic protocols?",options:["Reducing a user's account privileges","Altering server hardware specs","Forcing use of a weaker, older protocol version","Targeting IT staff facing layoffs"],answer:2,explanation:"The POODLE attack exploited downgrade behavior to force connections to fall back to SSL 3.0, which had known vulnerabilities, even when both client and server supported more secure TLS versions — defenses include disabling legacy protocol/cipher support entirely and implementing protocol version pinning where possible (e.g., TLS_FALLBACK_SCSV).",optionExplanations:["This isn't about account privileges; it's about protocol negotiation.","This is a protocol attack, not a hardware change.","Downgrade attacks like POODLE force a fallback to a weaker, exploitable protocol version.","This is a technical attack, not a social engineering scheme."]},
  {id:814,domain:A,question:"What is the purpose of geofencing in mobile device security?",options:["Encrypting GPS coordinates in transit","A shielding barrier blocking wireless signals","Building a fence around a data center","Restricting device actions based on location"],answer:3,explanation:"Organizations might configure MDM policies to automatically lock a device or disable camera/data access when it leaves an approved geographic boundary (e.g., a hospital's campus), or conversely trigger enhanced security requirements when a device is detected in a high-risk country — geofencing adds a location-based contextual layer to access and security policies.",optionExplanations:["Geofencing uses location to trigger policy, not encrypt coordinates.","This describes a Faraday cage, not a location-based control.","This is a software control, not a physical fence.","Geofencing can lock a device or restrict features once it leaves an approved area."]},
  {id:815,domain:O,question:"What is the purpose of conducting regular access reviews (user access recertification)?",options:["A single review conducted only during an annual scheduled external audit","Periodically verifying access rights are still appropriate","Inspecting the condition of ID badges","Reviewing access only for new hires"],answer:1,explanation:"Privilege creep occurs as employees change roles over time, often accumulating access rights from previous positions that are never revoked — regular (e.g., quarterly) access reviews catch this drift, ensuring the principle of least privilege is maintained over time rather than only at initial provisioning.",optionExplanations:["Effective reviews are ongoing, not just once during an audit.","Regular recertification catches privilege creep as roles change over time.","This is about logical permissions, not badge appearance.","Reviews cover existing employees' ongoing access, not just onboarding."]},
  {id:816,domain:T,question:"What is a Business Email Compromise (BEC) attack?",options:["Impersonating an executive to request a wire transfer","Physically breaching email servers","Any email from a company account","A spam filtering technique used to screen all incoming email messages"],answer:0,explanation:"BEC attacks often involve researching an organization (via LinkedIn, press releases) to identify the right executive to impersonate, then sending urgent, plausible requests (e.g., 'I need this wire transfer processed immediately, I'm in a meeting') to finance staff — BEC causes billions in losses annually and often bypasses technical controls since it relies purely on social engineering rather than malware.",optionExplanations:["BEC relies on impersonation and urgency to trick staff into fraudulent transfers.","This isn't a server compromise; it's social engineering via email.","BEC is a targeted fraud technique, not any business email.","This describes a defense, the opposite of the attack."]},
  {id:817,domain:A,question:"What is the purpose of an air-gapped network?",options:["Extra spacing for cooling airflow","A network physically isolated from unsecured networks","A redundant failover network","A wireless-only network"],answer:1,explanation:"Air-gapped networks (used for industrial control systems, classified government networks, or nuclear facility controls) eliminate remote network-based attack vectors entirely — but they're not immune to all threats, as demonstrated by Stuxnet, which crossed the air gap via infected USB drives, showing that physical/removable media controls remain critical even in air-gapped environments.",optionExplanations:["This is a cooling consideration, not a security architecture.","Air gaps remove remote network attack paths, though media like USB drives remain a risk.","Air-gapped networks are isolated production systems, not backup networks.","Air-gapping means physical disconnection, the opposite of wireless connectivity."]},
  {id:818,domain:T,question:"What is an insider threat?",options:["A threat that can always be traced to a foreign nation","A threat limited to internal messaging tools","A vulnerability only in internal software","Risk from those with authorized internal access"],answer:3,explanation:"Insider threats can be malicious (a disgruntled employee stealing data before leaving), negligent (an employee falling for phishing or misconfiguring a cloud bucket), or compromised (an external attacker using stolen insider credentials) — insider threats are particularly dangerous because the individual already has legitimate, trusted access, bypassing many perimeter-focused defenses.",optionExplanations:["Insider threats originate internally, regardless of nationality.","Insider threats can affect any asset, not just messaging.","This isn't about software vulnerabilities; it's about people with legitimate access.","Insiders already hold trusted access, bypassing many perimeter defenses."]},
  {id:819,domain:O,question:"What is the purpose of a disaster recovery (DR) test?",options:["Conducted only after an actual disaster","Performed once, right after the plan is written","A quiz testing employees' general home fire and safety knowledge","A periodic exercise validating the DR plan works"],answer:3,explanation:"DR tests range from tabletop walkthroughs to full failover tests (actually cutting over to a DR site) — regularly scheduled testing (annually at minimum, often more frequently for critical systems) catches issues like outdated runbooks, missing dependencies, or failed backups before they're discovered during an actual crisis when the stakes are highest.",optionExplanations:["Testing should happen before a disaster, to ensure readiness.","Plans and environments change, requiring ongoing periodic testing.","DR tests validate technical recovery, not general safety knowledge.","Regular testing catches outdated runbooks and failed backups before a real crisis."]},
  {id:820,domain:T,question:"What is a side-channel attack?",options:["Targeting a website's navigation menus","A backup attack automatically attempted after a failed attempt","An attack via a secondary network link","Exploiting timing or power leakage from hardware"],answer:3,explanation:"Timing attacks measure how long cryptographic operations take to infer information about secret keys; power analysis attacks measure a smart card's power consumption during encryption to extract key bits; Spectre/Meltdown exploited CPU speculative execution timing — side-channel attacks bypass the mathematical strength of an algorithm entirely by exploiting its physical implementation.",optionExplanations:["This is a hardware-level attack, not about UI elements.","This is a distinct attack category, not a fallback method.","This isn't about network paths; it's about physical information leakage.","Side-channel attacks exploit implementation details like timing, not algorithm flaws."]},
  {id:821,domain:G,question:"What is the purpose of a data classification policy?",options:["Restricting allowed file formats","Restricting data to one physical facility","Organizing data alphabetically by filename","Categorizing data by sensitivity level"],answer:3,explanation:"Data classification (often required by frameworks like FedRAMP, HIPAA) ensures that highly sensitive data (PII, financial records) receives stronger protections — encryption, restricted access, audit logging — while public data requires minimal controls, allowing organizations to allocate security resources proportionally to actual risk rather than applying uniform (and often inefficient) protection to all data.",optionExplanations:["File format rules are a separate technical control.","Classification concerns handling requirements, not physical storage location.","Classification is based on sensitivity, not alphabetical order.","Sensitivity tiers like Confidential or Restricted determine required handling controls."]},
  {id:822,domain:O,question:"What is the purpose of a security operations center (SOC) shift handoff process?",options:["Coordinating the rearrangement of physical desks within the SOC's shared workspace","Ensuring continuity between outgoing and incoming shifts","A one-time procedure at SOC opening","Rotating parking spots weekly"],answer:1,explanation:"Effective handoffs include a summary of ongoing investigations, unresolved alerts, any planned maintenance windows, and known issues — without proper handoff, an incident detected late in one shift might lose momentum or context when picked up (or missed) by the next shift, delaying response.",optionExplanations:["This isn't about workspace logistics.","Handoffs preserve context on ongoing investigations so nothing is missed between shifts.","Handoffs occur at every shift change, not just once.","Parking is unrelated to operational continuity."]},
  {id:823,domain:T,question:"What is a rootkit?",options:["A standard admin maintenance toolkit","A starter kit sold to hobbyists for assembling hardware","A signed installer from a trusted vendor","Malware hiding privileged access from the OS"],answer:3,explanation:"Kernel-level rootkits modify core OS components to intercept and falsify system calls, hiding malicious files, processes, and network connections from normal detection tools — because they operate at such a privileged level, rootkits are notoriously difficult to detect and often require specialized tools or a full OS reinstall to fully remove.",optionExplanations:["This describes legitimate tools, the opposite of a rootkit.","This is wordplay unrelated to physical hardware kits.","Rootkits are malicious, unlike a legitimate signed installer.","Rootkits operate at a privileged level to conceal their own presence."]},
  {id:824,domain:A,question:"What is the function of an HSM (Hardware Security Module) in an organization's cryptographic infrastructure?",options:["General-purpose backup storage","A tamper-resistant device that secures cryptographic keys","Logging employee badge access","Physically locking the entryway doors leading into a guarded server room"],answer:1,explanation:"HSMs are used for high-value key management scenarios like Certificate Authority root key protection, payment processing (PCI HSMs), and code signing — they're designed with tamper-evident/tamper-responsive mechanisms (some self-destruct keys if physical tampering is detected) and perform cryptographic operations internally so the private key material never leaves the hardware boundary.",optionExplanations:["HSMs protect key material, not general file backup.","HSMs generate and store keys so private key material never leaves the hardware.","Badge logging is physical security, unrelated to key management.","This is a physical access control, not a cryptographic device."]},
  {id:825,domain:O,question:"What is the purpose of the 'containment' phase in the incident response lifecycle?",options:["Limiting an incident's scope while preserving evidence","Gathering the IR team in one room","Deleting all incident evidence","Publishing the final incident report"],answer:0,explanation:"Containment strategies range from short-term (isolating an infected host from the network while preserving its memory state for forensics) to long-term (rebuilding affected systems from clean images) — the goal is to stop the bleeding without destroying evidence needed to fully understand and remediate the root cause.",optionExplanations:["Containment stops the spread while preserving evidence needed for analysis.","This isn't about team logistics; it's about limiting technical scope.","Containment preserves evidence; it doesn't destroy it.","Reporting happens in the post-incident phase, not during containment."]},
  {id:826,domain:T,question:"What is a botnet?",options:["A redundant backup network maintained privately by internet providers","Compromised devices controlled remotely for attacks","A robotics manufacturing network","A legitimate chatbot network"],answer:1,explanation:"The Mirai botnet famously compromised hundreds of thousands of IoT devices (cameras, routers) with weak default credentials, using their combined bandwidth to launch some of the largest DDoS attacks recorded — botnets derive their power from scale, allowing attackers to harness massive distributed computing/bandwidth resources without owning any of the infrastructure themselves.",optionExplanations:["Botnets are malicious infrastructure, not ISP backup systems.","Botnets give attackers massive distributed capability like DDoS power from compromised devices.","This is wordplay unrelated to robot manufacturing.","This describes legitimate automation, not malicious compromised devices."]},
  {id:827,domain:P,question:"What is the purpose of a records of processing activities (RoPA) document under GDPR?",options:["A physical logbook recording visitor names and arrival times","Daily employee attendance records","An inventory of personal data processing activities","A list of purchased IT equipment"],answer:2,explanation:"RoPA documentation provides accountability and transparency, helping organizations (and regulators during audits) understand the full scope of personal data processing across the enterprise — it's foundational for demonstrating GDPR compliance and is often a prerequisite for conducting effective privacy impact assessments.",optionExplanations:["Visitor logs are physical security records, unrelated to GDPR documentation.","This isn't attendance tracking; it documents data processing.","RoPA documents processing activities as required under GDPR Article 30.","Equipment records are unrelated to data processing documentation."]},
  {id:828,domain:T,question:"What is a zero-day exploit?",options:["An exploit developed in zero days","An exploit usable only on release day","Exploiting an unpatched, unknown vulnerability","A vulnerability that has existed since a system was deployed"],answer:2,explanation:"Zero-day vulnerabilities are especially dangerous because traditional signature-based defenses and patches don't yet exist — they're often discovered and weaponized by sophisticated threat actors (nation-states, well-resourced criminal groups) and sold on underground markets for substantial sums before vendors become aware and can issue patches.",optionExplanations:["Development can take time; 'zero-day' refers to defenders' warning, not build time.","Zero-days often remain usable well past the day they're first used.","No patch exists yet because defenders have zero days of advance warning.","'Zero-day' describes lack of warning, not the system's age."]},
  {id:829,domain:A,question:"What is the purpose of secure boot in modern computing devices?",options:["Making a device boot faster","Encrypting only the boot password prompt","Booting into a sandboxed guest mode","Verifying each boot component is signed and trusted"],answer:3,explanation:"Secure boot establishes a chain of trust starting from the hardware root of trust (often anchored in the TPM or UEFI firmware) through each subsequent boot stage — if malware (like a bootkit) attempts to tamper with any component in this chain, the signature verification fails and the system refuses to boot that compromised component, preventing pre-OS-level persistence.",optionExplanations:["Secure boot verifies integrity, adding overhead rather than speeding boot.","Secure boot validates signatures throughout, not just a password prompt.","This isn't about a guest session; it verifies the primary boot chain.","Signature verification at each stage blocks bootkits from tampering with the boot chain."]},
  {id:830,domain:O,question:"What is the purpose of a vulnerability management program's risk-based prioritization?",options:["Patching every single identified vulnerability in strict alphabetical CVE order","Prioritizing by severity, exploitability, and asset criticality","Patching only publicly reported vulnerabilities","Ignoring all low-severity vulnerabilities"],answer:1,explanation:"A critical CVSS 9.8 vulnerability on an internal, isolated test server with no internet exposure may actually be lower priority than a CVSS 7.5 vulnerability on an internet-facing production server with a known public exploit — risk-based prioritization (using frameworks like EPSS alongside CVSS) ensures limited patching resources address the vulnerabilities posing the greatest actual organizational risk first.",optionExplanations:["CVE ID order has no relation to actual risk.","Risk-based prioritization weighs exposure and exploit availability alongside severity scores.","Vulnerability source doesn't determine remediation priority.","Low-severity issues can still pose risk and shouldn't be ignored entirely."]},
  {id:831,domain:T,question:"What is a malicious USB drop attack?",options:["Leaving infected USB drives for targets to find","Physical damage from repeated USB use","A retail price-drop marketing tactic","An approved technique for securely wiping old USB drives"],answer:0,explanation:"Attackers might leave USB drives labeled 'Salary Information' or 'Confidential' in a company parking lot — curiosity drives employees to plug them into work computers, where autorun malware or a malicious HID (Human Interface Device) emulation script executes automatically, demonstrating how physical and psychological attack vectors combine.",optionExplanations:["Curiosity leads victims to plug in a found drive, triggering autorun malware.","This is a social engineering and delivery technique, not port damage.","This is wordplay; the attack involves leaving devices, not pricing.","This describes secure disposal, not a malicious attack."]},
  {id:832,domain:A,question:"What is the purpose of a Web Application Firewall (WAF) in protecting web applications?",options:["A version-controlled backup of an application's source code","Blocking traffic from specific countries only","A physical firewall appliance in a rack","Filtering malicious HTTP traffic like SQLi and XSS"],answer:3,explanation:"WAFs (Cloudflare, AWS WAF, ModSecurity) operate at Layer 7, inspecting actual HTTP request content against rule sets (signature-based or anomaly-based) to block malicious payloads before they reach the application — providing a critical compensating control for vulnerabilities that haven't yet been patched in the application code itself.",optionExplanations:["WAFs filter live traffic; they don't back up code.","Geo-blocking can be one feature, but the core function is content filtering.","WAFs operate at the application layer, unlike a physical network appliance.","WAFs inspect HTTP content to block OWASP Top 10-style attacks."]},
  {id:833,domain:O,question:"What is the purpose of an incident response retainer agreement with a third-party firm?",options:["A guarantee to never report incidents","Eliminating the need for internal IR staff","A pre-arranged contract for rapid external IR access","A fee paid to local police"],answer:2,explanation:"Organizations without 24/7 in-house deep forensic capability often establish retainers with firms like Mandiant or CrowdStrike Services beforehand — this guarantees rapid response time (often contracted SLAs of hours, not days) and avoids the costly delay of vetting and negotiating contracts while actively under attack.",optionExplanations:["Legal reporting obligations exist independently of any retainer.","Retainers typically augment, not replace, internal IR capability.","Pre-negotiated retainers avoid costly delays in vendor selection during a crisis.","This is a contract with a private IR firm, not law enforcement."]},
  {id:834,domain:T,question:"What is a malvertising attack?",options:["Spam email marketing legitimate products","Generating fake positive product reviews","Physically targeting the offices of major online ad agencies","Distributing malware through legitimate ad networks"],answer:3,explanation:"Attackers purchase ad space through legitimate ad networks (which often have automated, less-vetted approval processes) and embed malicious code or redirects in the ad creative — drive-by-download malvertising can compromise visitors of even well-known, reputable websites without any click, just by loading a page containing the malicious ad.",optionExplanations:["This isn't email spam; it's malicious content via ad networks.","Fake reviews are a different, unrelated deceptive practice.","This is a digital attack vector, not a physical office attack.","Malvertising can compromise visitors of trusted sites via the ad supply chain."]},
  {id:835,domain:G,question:"What is the concept of 'security through obscurity' and why is it generally considered insufficient as a primary defense?",options:["Concealing configurations from auditors","A tiered government classification system for sensitive information","A peer-reviewed cryptographic design principle","Relying on hiding details instead of strong controls"],answer:3,explanation:"Examples include running services on non-standard ports hoping attackers won't find them, or using a custom, unvetted encryption algorithm instead of a proven one — while obscurity can be one layer in defense-in-depth, relying on it alone fails catastrophically once the secret is discovered (e.g., through scanning, reverse engineering, or insider leak), since there's no underlying robust control.",optionExplanations:["Hiding configs from auditors undermines governance rather than describing this concept.","This isn't a classification framework; it's a design anti-pattern.","Legitimate cryptography uses open, peer-reviewed standards, the opposite of secrecy-based design.","This fails once the hidden detail is discovered, per Kerckhoffs's principle."]},
  {id:836,domain:O,question:"What is the purpose of network flow data (NetFlow/sFlow) analysis in security monitoring?",options:["Analyzing traffic metadata without full packet content","A software tool used by HR departments to manage workflow approvals","An ISP billing measurement technique","Measuring data center cooling water flow"],answer:0,explanation:"NetFlow data is much smaller than full packet captures, making it practical to retain for long periods — security teams can use it to identify unusual data exfiltration volumes, detect communication with known malicious IPs, or trace lateral movement patterns during an investigation, even without the full packet content that would be needed for deep content inspection.",optionExplanations:["Flow metadata is compact enough to retain long-term for spotting exfiltration or lateral movement.","This isn't business workflow; it's network traffic metadata.","ISPs may use flow data for billing, but the security use is pattern analysis.","This is network metadata, unrelated to physical cooling."]},
  {id:837,domain:T,question:"What is a man-in-the-middle (MITM) attack at a fundamental level?",options:["A business negotiation tactic","Secretly intercepting communication between two parties","Targeting only middleware software","Requiring a middle-management job title"],answer:1,explanation:"MITM can occur at many layers — ARP poisoning (Layer 2), rogue WiFi APs, BGP hijacking, or compromised/malicious TLS certificates — the unifying theme is that the attacker positions themselves transparently in the communication path, often able to eavesdrop, modify data in transit, or impersonate one or both parties without either realizing the interception is occurring.",optionExplanations:["This isn't a negotiation strategy; it's a technical attack pattern.","MITM attackers position themselves in the path, able to eavesdrop or alter data.","MITM applies broadly, not specifically to middleware.","This is wordplay unrelated to organizational hierarchy."]},
  {id:838,domain:A,question:"What is the purpose of implementing rate limiting on an API or login endpoint?",options:["A caching feature with no security purpose","Capping requests to block brute force and DoS","A billing method used to calculate monthly API charges","Limiting file download transfer speed"],answer:1,explanation:"A login endpoint with rate limiting (e.g., max 5 attempts per minute per IP) significantly slows down brute force and credential stuffing attacks, making them impractical at scale, while API rate limiting prevents a single client from monopolizing resources or scraping data en masse — proper rate limiting also helps protect against application-layer DoS attacks.",optionExplanations:["Rate limiting has clear security value against automated abuse.","Capping request frequency makes brute force and credential stuffing impractical at scale.","Billing rate is a separate business concept from request throttling.","Rate limiting applies broadly, not just to download speed."]},
  {id:839,domain:O,question:"What is the purpose of a security control self-assessment versus an independent audit?",options:["Self-assessments performed by internal staff are always considered more reliable","Self-assessments are legally mandated, audits are optional","No practical difference exists between them","Internal ongoing review versus external independent review"],answer:3,explanation:"Self-assessments are valuable for continuous internal monitoring and catching issues early at lower cost, but they can suffer from bias or blind spots since the assessor may be evaluating their own work — independent audits (SOC 2, ISO 27001 certification audits) provide external validation with greater credibility for customers, regulators, and business partners specifically because of their objectivity.",optionExplanations:["Independent audits generally offer higher assurance due to objectivity.","Requirements vary; neither is universally mandated.","These serve distinct, complementary purposes with different assurance levels.","Self-assessment offers frequent internal monitoring; audits provide external, credible validation."]},
  {id:840,domain:T,question:"What is a heap spray attack technique?",options:["A memory compression technique","A volumetric packet-flooding attack","A routine garbage collection process run by the OS","Filling heap memory with shellcode and NOP sleds"],answer:3,explanation:"Because exact memory addresses are often unpredictable (especially with ASLR), heap spraying increases the attacker's odds of success by saturating large swaths of memory with shellcode preceded by long NOP sled sequences — if the corrupted pointer lands anywhere within the sprayed region, execution likely slides into the malicious payload, commonly used in browser/JavaScript engine exploits.",optionExplanations:["This isn't compression; it's filling memory with malicious payload.","This is a memory exploitation technique, unrelated to network flooding.","This is an offensive technique, not routine garbage collection.","Spraying memory with shellcode raises the odds a hijacked pointer lands in the payload."]},
  {id:841,domain:A,question:"What is the purpose of a sandbox environment in malware analysis?",options:["A children's play area on campus","An isolated environment for observing suspicious code","A backup environment for DR tests","A staging environment for UI testing"],answer:1,explanation:"Dynamic malware analysis sandboxes (Cuckoo Sandbox, Joe Sandbox, ANY.RUN) execute suspicious files in a monitored virtual environment, recording file system changes, network connections, and process behavior — this allows analysts to understand malware capabilities and IOCs (indicators of compromise) without risking infection of real systems, though sophisticated malware may include sandbox-evasion techniques to detect and avoid analysis.",optionExplanations:["This is a technical tool, not a literal recreational sandbox.","Sandboxes safely execute and observe malware behavior without risking production systems.","DR environments serve continuity, a different purpose from malware analysis.","UI staging is unrelated to security malware analysis."]},
  {id:842,domain:T,question:"What is a DNS amplification attack?",options:["A network tuning technique that improves DNS resolution speed and reliability","Amplifying wireless signal strength","Spoofed small queries triggering large replies at a victim","A method for scaling DNS infrastructure"],answer:2,explanation:"Attackers send small DNS queries (e.g., 60 bytes) with a spoofed source IP set to the victim's address, to open DNS resolvers that return large responses (e.g., 3000+ bytes) — this amplification factor (potentially 50x or more) combined with reflection (the response goes to the spoofed victim, not the attacker) makes DNS amplification a powerful and popular DDoS technique.",optionExplanations:["This degrades performance for the victim, not improves it.","This is a traffic-volume attack, unrelated to RF signal amplification.","Spoofing plus amplification turns small requests into a massive flood at the victim.","This describes malicious DDoS traffic, not legitimate scaling."]},
  {id:843,domain:O,question:"What is the purpose of conducting red team versus blue team versus purple team exercises?",options:["Different shifts of the same SOC team","Only the blue team's findings are ever considered valid in assessments","Red attacks, blue defends, purple facilitates collaboration","Just different colored team uniforms"],answer:2,explanation:"Pure red team exercises test detection/response capability adversarially (sometimes without blue team's prior knowledge), while purple teaming intentionally breaks down the wall between offense and defense — red and blue work together in real time, with red team explaining techniques as they execute them so blue team can immediately validate and tune their detection capability, accelerating the overall security improvement cycle.",optionExplanations:["These are functionally distinct roles, not shift rotations.","Both red and blue team findings offer valuable, complementary insight.","Purple teaming breaks down walls between offense and defense to speed improvement.","Each team has distinct objectives and methods, not just uniform colors."]},
  {id:844,domain:T,question:"What is an attack surface, and why is reducing it important?",options:["All potential entry points for an attacker","Physical floor space of a server rack","Only firewall configuration settings","Only refers to malware delivered via infected USB drives"],answer:0,explanation:"Attack surface reduction techniques include disabling unused services, removing unnecessary software, closing unused ports, and minimizing exposed APIs — every additional feature, open port, or running service represents another potential vector an attacker could exploit, so the security principle is to minimize what's exposed to only what's functionally necessary.",optionExplanations:["A smaller attack surface means fewer opportunities for entry or data extraction.","This is a conceptual measure, not a physical floor dimension.","Attack surface extends beyond firewalls to apps, APIs, and people.","Attack surface covers all exposure points, not just USB delivery."]},
  {id:845,domain:G,question:"What is the purpose of a risk register?",options:["A documented inventory of organizational risks and owners","A list of employees with security clearances","An approved vendor procurement list","A log of every login attempt"],answer:0,explanation:"Risk registers provide visibility for risk management decision-making — leadership can review the register to see, for example, that an unpatched legacy system represents a 'High' likelihood/'High' impact risk currently being mitigated through network segmentation while a permanent fix is planned, supporting informed risk acceptance, transfer, mitigation, or avoidance decisions.",optionExplanations:["The register tracks likelihood, impact, and mitigation status to support risk decisions.","This is a personnel clearance list, not a risk tracking document.","Vendor lists are a procurement artifact, distinct from risk tracking.","Login logs are operational monitoring data, not strategic risk documentation."]},
  {id:846,domain:O,question:"What is the purpose of establishing escalation procedures within an incident response plan?",options:["A career promotion track for analysts","A process for routing routine internal help desk tickets","HR procedures for approving raises","Criteria for notifying leadership based on severity"],answer:3,explanation:"Escalation procedures specify, for example, that any incident involving suspected data breach of customer PII must immediately notify legal counsel and the CISO within 1 hour, while a routine malware detection on an isolated workstation follows standard analyst-level handling — clear escalation criteria prevent both under-escalation (executives unaware of a major breach) and over-escalation (executives drowning in minor alert noise).",optionExplanations:["Career advancement is an HR process, unrelated to incident notification.","Formal escalation covers incident severity, a broader scope than help desk routing.","Escalation governs notification chains, not compensation decisions.","Clear criteria prevent both under- and over-notifying stakeholders during an incident."]},
  {id:847,domain:T,question:"What is a pretexting social engineering attack?",options:["Occurring only before any SMS is sent","Targeting only SMS infrastructure","Fabricating a false scenario to manipulate a victim","A structured QA method used for testing software releases"],answer:2,explanation:"Example: an attacker calls the help desk claiming to be a traveling executive who's locked out and urgently needs a password reset, fabricating enough plausible detail (correct employee ID, knowledge of org structure) to convince the help desk technician to bypass normal verification procedures — pretexting relies on a convincing, prepared backstory rather than urgency or fear alone.",optionExplanations:["This is wordplay unrelated to SMS timing.","Pretexting can occur over any channel, not just SMS.","A convincing, prepared false backstory persuades the victim to divulge information or bypass checks.","This isn't QA testing; it's a social engineering technique."]},
  {id:848,domain:A,question:"What is the purpose of implementing TLS mutual authentication (mTLS)?",options:["Doubling encryption key strength automatically","Both client and server authenticate via certificates","A backup TLS configuration activated only during maintenance windows","A protocol for negotiating transaction prices"],answer:1,explanation:"mTLS is commonly used for service-to-service authentication in zero trust architectures and API security (microservices communicating within a service mesh) — since both parties present and validate certificates, it provides strong mutual identity assurance, ensuring a malicious or unauthorized client can't connect even if it knows the correct endpoint URL.",optionExplanations:["mTLS adds client authentication; it doesn't double key strength.","Mutual certificate validation gives strong bidirectional identity assurance, common in zero trust.","mTLS is an ongoing configuration, not solely a failover mechanism.","This isn't about pricing; it's about cryptographic identity verification."]},
  {id:849,domain:O,question:"What is the purpose of conducting a root cause analysis (RCA) after a security incident?",options:["Calculating the financial cost of IR","Identifying which employee to blame","Finding the fundamental cause to prevent recurrence","Only performed for physical breaches"],answer:2,explanation:"RCA techniques like the '5 Whys' help teams move past surface-level findings (e.g., 'malware got in through a phishing email') to deeper systemic issues (e.g., 'why did the email bypass filtering? Why wasn't MFA enforced? Why was the employee's training overdue?') — addressing only symptoms without RCA often leads to repeat incidents from the same underlying gaps.",optionExplanations:["Cost tracking is separate from RCA's causal analysis focus.","RCA focuses on systemic causes, not assigning individual blame.","Techniques like the '5 Whys' dig past symptoms to the systemic root issue.","RCA applies broadly across incident types, not just physical breaches."]},
  {id:850,domain:T,question:"What is a watering hole versus drive-by download attack — what's the key relationship?",options:["Watering holes always require manual downloads","Two entirely unrelated techniques that almost never appear together in campaigns","Drive-by downloads occur only via email attachments","A watering hole often delivers malware via drive-by download"],answer:3,explanation:"In a typical watering hole attack chain, attackers first compromise a legitimate, trusted website frequented by their target group, then embed exploit code that performs a drive-by download — automatically attempting to exploit unpatched browser or plugin vulnerabilities to silently install malware the moment a vulnerable visitor loads the page, with no click or download action required from the victim.",optionExplanations:["Drive-by downloads specifically need no manual download or run action.","These techniques are frequently combined in real attack campaigns.","Drive-by downloads occur through compromised web pages, not email attachments.","The compromised site auto-exploits browser flaws the moment a victim loads the page."]},
  {id:851,domain:G,question:"What is the purpose of conducting threat modeling during the software design phase?",options:["Identifying threats during design to build in controls","Modeling performance under heavy load","A modeling technique used to produce marketing pitch materials","Creating 3D network topology diagrams"],answer:0,explanation:"Frameworks like STRIDE (Spoofing, Tampering, Repudiation, Information disclosure, Denial of service, Elevation of privilege) help development teams systematically consider 'what could go wrong' for each component during design — identifying and addressing security issues at the design phase is dramatically cheaper than discovering and fixing them after deployment or, worse, after an actual breach.",optionExplanations:["Frameworks like STRIDE find design-phase security gaps, which are cheaper to fix early.","This addresses performance/load testing, not security threats.","Threat modeling is a security practice, unrelated to marketing.","This is an analytical process, not visual network diagramming."]},
  {id:852,domain:O,question:"What is the purpose of a security exception/risk acceptance process?",options:["A disciplinary process for terminating employees","A fully automated process that grants every exception request","Documenting and tracking non-compliance with sign-off","Permanently bypassing all security policies"],answer:2,explanation:"Example: a legacy application requiring an outdated, vulnerable protocol can't be immediately replaced due to business constraints — a documented exception with compensating controls (network isolation, enhanced monitoring) and an executive risk owner's sign-off ensures the risk is consciously accepted and tracked, rather than silently ignored or indefinitely deferred without accountability.",optionExplanations:["This is a risk governance process, not employee discipline.","Exceptions require human risk owner review, not automated approval.","A documented exception with compensating controls ensures risk is consciously accepted and tracked.","Exception processes formally track deviations, not permanently ignore policy."]},
  {id:853,domain:T,question:"What is a Distributed Reflection Denial of Service (DRDoS) attack?",options:["Reflecting sunlight to damage cooling systems","A DoS from a single attacking machine","A legitimate load testing technique","Spoofing a victim's IP to flood them via third-party servers"],answer:3,explanation:"DRDoS combines reflection (using legitimate, innocent third-party servers as unwitting amplifiers) with spoofing (hiding the true attacker identity) — DNS amplification and NTP amplification attacks are specific examples of DRDoS that have been used to generate some of the largest DDoS attacks ever recorded, since the 'reflectors' are typically high-bandwidth, legitimate servers.",optionExplanations:["This is a network attack, unrelated to physical/environmental damage.","DRDoS is inherently distributed, using many reflector servers.","DRDoS is malicious and unauthorized, unlike legitimate load testing.","Reflection and spoofing combine to generate massive traffic while hiding the attacker."]},
  {id:854,domain:A,question:"What is the purpose of implementing a bastion host (jump server)?",options:["A physical guard station at a building","A host for public marketing websites","A hardened single entry point for admin access","A backup server activated only during failover and maintenance"],answer:2,explanation:"Instead of allowing direct SSH/RDP access to every internal server from the internet, administrators connect first to the bastion host (which is heavily hardened, monitored, and often requires MFA), then jump from there to internal systems — this consolidates administrative access through a single auditable, well-defended chokepoint rather than exposing many systems directly.",optionExplanations:["Bastion hosts are a network control, not physical building security.","Bastion hosts control internal admin access, the opposite of public web hosting.","Consolidating admin access through one hardened, monitored chokepoint improves auditability.","Bastion hosts serve ongoing access control, not just failover."]},
  {id:855,domain:O,question:"What is the purpose of automated patch management systems?",options:["Scheduling physical HVAC maintenance","Automating identification and deployment of security patches","Automatically writing new application code","A backup and recovery tool unrelated to deploying security patches"],answer:1,explanation:"Automated patch management (WSUS, SCCM, Ivanti) can identify missing patches across thousands of endpoints, deploy them in scheduled maintenance windows, and report on patch compliance status — given that unpatched known vulnerabilities remain one of the most common breach causes, automation significantly reduces the time window during which systems remain exposed to known, exploitable flaws.",optionExplanations:["This is software patching, not physical facility maintenance.","Automation reduces the exposure window for known, exploitable vulnerabilities.","Patch management deploys vendor fixes; it doesn't write new code.","Patch management focuses on updates, not general backup and recovery."]},
  {id:856,domain:T,question:"What is a smishing attack?",options:["A legitimate SMS-based 2FA system","Compromising smart home IoT devices","Phishing conducted via SMS text messages","A phishing-style attack conducted through office fax machines"],answer:2,explanation:"Smishing messages often impersonate banks, delivery services, or government agencies ('Your package couldn't be delivered, click here to reschedule') — SMS messages can be particularly effective since mobile users may have lower guard against text-based deception compared to email, and links are harder to inspect/hover-preview on mobile devices.",optionExplanations:["This describes a legitimate security feature, the opposite of smishing.","'Smishing' specifically refers to SMS phishing, not IoT compromise.","Smishing exploits users' lower guard against text-based deception on mobile devices.","Smishing is SMS-based, not fax-based."]},
  {id:857,domain:P,question:"What is the purpose of a service organization control (SOC) 2 Type II report?",options:["Verifying controls operated effectively over time","A marketing brochure for prospective clients","A fire and safety code compliance report","A report verifying annual revenue"],answer:0,explanation:"SOC 2 Type II differs from Type I (which only verifies controls were suitably designed at a single point in time) by testing operating effectiveness over a period (typically 6-12 months) — this distinction matters because a control could be well-designed on paper but not consistently followed in practice, which Type II's extended observation period is specifically designed to catch.",optionExplanations:["Type II tests operating effectiveness over months, unlike a point-in-time design check.","SOC 2 is an audit deliverable, not marketing material.","SOC 2 addresses security controls, not fire/safety code compliance.","SOC 2 addresses security, not financial revenue reporting."]},
  {id:858,domain:T,question:"What is an on-path attack (formerly known as man-in-the-middle)?",options:["Requires physical presence on a delivery route","A legitimate latency optimization technique","Positioning between two parties to intercept data","An attack that targets only the physical postal mail system"],answer:2,explanation:"CompTIA's updated terminology ('on-path attack') describes the same concept previously called 'man-in-the-middle' — emphasizing the attacker's network position relative to the communication path rather than gendered terminology, while the underlying threat (covert interception/manipulation of communications between trusting parties) remains the same.",optionExplanations:["This is a network attack, unrelated to physical courier routes.","On-path positioning describes a malicious vector, not legitimate optimization.","The attacker's network position lets it covertly intercept or alter communications.","'Path' here refers to network data flow, not literal postal mail."]},
  {id:859,domain:A,question:"What is the purpose of network segmentation between IT and OT (Operational Technology) environments?",options:["Isolating industrial control systems from IT","Providing no meaningful security benefit","Illegal to implement under most industrial safety regulations","Purely an org-chart reporting structure"],answer:0,explanation:"The 2021 Colonial Pipeline incident demonstrated the risk when IT/OT separation is insufficient — though the OT systems weren't directly compromised, the company proactively shut down pipeline operations due to IT compromise concerns, highlighting how IT/OT segmentation (using firewalls, data diodes, and the Purdue Model architecture) is critical since OT systems often can't be patched/secured the same way as IT systems due to uptime and safety requirements.",optionExplanations:["Segmentation limits how far an IT compromise can spread into critical infrastructure.","Segmentation provides substantial security benefit, not just cost savings.","Segmentation is a recommended, often required practice, not illegal.","This is a technical security control, not an org chart designation."]},
  {id:860,domain:O,question:"What is the purpose of a security metrics dashboard for executive reporting?",options:["Used only by marketing for ad metrics","Displaying individual analyst performance scores","Translating security data into business-relevant metrics","A general HR tool used mainly for tracking vacation schedules"],answer:2,explanation:"Effective executive dashboards avoid overwhelming leadership with raw technical detail (like CVE counts) and instead present trends and business risk context (e.g., 'critical vulnerability remediation time has decreased 40% this quarter, but third-party vendor risk remains elevated') — this enables non-technical executives to understand security posture and make informed budget/risk decisions.",optionExplanations:["Security dashboards serve leadership risk decisions, unrelated to marketing.","Executive dashboards focus on organizational risk, not individual performance.","Translating technical detail into business context helps executives make budget decisions.","Vacation tracking is an HR function, unrelated to security reporting."]},
  {id:861,domain:T,question:"What is a cryptojacking attack?",options:["Encrypting exchange servers for ransom","A legitimate opt-in cloud mining service","Unauthorized use of resources to mine cryptocurrency","Stealing cryptocurrency wallet files directly"],answer:2,explanation:"Cryptojacking malware or malicious JavaScript (running in a compromised website) silently consumes victim CPU/GPU resources to mine cryptocurrency for the attacker's benefit — symptoms include unexplained high CPU usage, system slowdown, and increased electricity costs; while less immediately destructive than ransomware, it represents unauthorized resource theft and can indicate broader compromise.",optionExplanations:["This describes ransomware, not resource-theft cryptojacking.","Legitimate mining involves consent and payment; cryptojacking is covert and unauthorized.","Cryptojacking silently consumes CPU/GPU resources for the attacker's mining benefit.","Cryptojacking abuses computing power rather than stealing existing wallet contents."]},
  {id:862,domain:G,question:"What is the purpose of the principle of 'fail securely' (fail closed) in system design?",options:["Granting access automatically on failure","Guaranteeing a system never fails","Defaulting to deny access on failure","Failing as loudly as possible regardless of impact"],answer:2,explanation:"A fail-secure access control system that loses connection to its authentication server should default to denying entry (even if inconvenient) rather than failing 'open' and granting unrestricted access — though this principle must be balanced against safety-critical systems (like fire door locks) where failing open may be required for life safety, illustrating the security-vs-safety tradeoff designers must navigate.",optionExplanations:["This describes 'fail open,' the opposite of fail-secure.","No system can guarantee zero failure; the principle addresses behavior during failure.","Defaulting to deny access accepts an availability tradeoff to preserve security.","Fail-secure concerns the access decision, not just failure visibility."]},
  {id:863,domain:O,question:"What is the purpose of conducting a gap analysis against a security framework (e.g., NIST CSF)?",options:["A one-time analysis never repeated","Performed only during company formation","Analyzing physical structural gaps in a server room's raised flooring","Comparing practices against a framework to find deficiencies"],answer:3,explanation:"A gap analysis against NIST CSF's five functions (Identify, Protect, Detect, Respond, Recover) might reveal that an organization has strong 'Protect' controls (firewalls, access control) but weak 'Detect' and 'Respond' capabilities (no SIEM, undefined IR plan) — this informs where to prioritize investment to achieve more balanced, comprehensive security maturity.",optionExplanations:["Frameworks and environments evolve, requiring periodic reassessment.","Gap analyses are valuable at any maturity stage, not just formation.","This is a maturity assessment, not physical flooring.","Comparing current practices to a framework like NIST CSF reveals where to prioritize investment."]},
  {id:864,domain:T,question:"What is a replay attack?",options:["Replaying recorded video surveillance footage","A legitimate session resumption mechanism","A method for backing up database transactions for QA testing","Retransmitting an intercepted valid token to gain access"],answer:3,explanation:"If a system doesn't use proper anti-replay measures (timestamps, nonces, sequence numbers), an attacker who intercepts a legitimate authentication request or financial transaction can simply resend that exact same captured data later to be authenticated or repeat the transaction fraudulently — defenses include timestamping requests, using single-use nonces, and implementing short validity windows for tokens.",optionExplanations:["This is a network attack on data, unrelated to camera footage.","Legitimate resumption uses freshness guarantees; replay exploits their absence.","This describes legitimate testing, the opposite of the malicious attack.","Without nonces or timestamps, a captured token can be resent to gain access later."]},
  {id:865,domain:A,question:"What is the purpose of implementing application allowlisting (whitelisting)?",options:["A backup list for reinstallation later","A list of permitted websites to browse","Only pre-approved applications are allowed to run","Vendors approved for license purchases"],answer:2,explanation:"Unlike blocklisting (denying known-bad applications, which fails against new/unknown threats), allowlisting (using tools like AppLocker or Windows Defender Application Control) takes a default-deny stance — only explicitly approved applications can execute, providing strong protection against zero-day malware and unauthorized software installation, though it requires more administrative overhead to maintain the approved list as legitimate software needs change.",optionExplanations:["Allowlisting actively controls execution, not a reinstall backup list.","Website allowlisting is related but distinct from application execution control.","Default-deny allowlisting is especially effective against zero-day and unknown malware.","Vendor approval is a procurement process, distinct from execution control."]},
  {id:866,domain:O,question:"What is the purpose of conducting a tabletop exercise specifically focused on ransomware scenarios?",options:["A marketing exercise designed to sell cyber insurance products","Deploying live ransomware on production systems","Testing physical guards and door locks","Simulating a ransomware scenario in discussion form"],answer:3,explanation:"Ransomware tabletop exercises walk through difficult decisions in advance — who has authority to decide on ransom payment, how to communicate with customers/regulators during an outage, whether cyber insurance covers the incident, and how to determine if backups are viable for recovery — making these decisions calmly beforehand is far more effective than improvising during an actual, high-pressure ransomware crisis.",optionExplanations:["Tabletops are internal preparedness activities, not sales efforts.","Tabletops are discussion-based, never involving live malware deployment.","Tabletops test decision-making, not physical security.","Walking through hard decisions calmly beforehand beats improvising during a real crisis."]},
  {id:867,domain:T,question:"What is a credential harvesting attack?",options:["An anonymous employee feedback survey","Collecting usernames and passwords via fake pages","Securely backing up a password database","An attack that physically clones an employee's RFID access badge"],answer:1,explanation:"Credential harvesting phishing pages mimic legitimate login portals (Office 365, banking sites) to capture entered credentials, which are then used for account takeover, sold on dark web markets, or used as a foothold for further attacks like credential stuffing against other services — harvested credentials are among the most valuable and commonly traded commodities in cybercrime.",optionExplanations:["This describes a legitimate HR process, unrelated to credential theft.","Fake login pages capture credentials for account takeover or resale.","This is theft, not a secure backup process.","This is a digital theft attack, not physical badge cloning."]},
  {id:868,domain:P,question:"What is the purpose of obtaining cyber liability insurance?",options:["Covering only fire, flood, or theft damage","A false claim that insurance replaces technical security controls","Mitigating financial costs of a cyber incident","A policy every employee must personally buy"],answer:2,explanation:"Cyber insurance can cover costs like forensic investigation, customer notification, credit monitoring services, legal defense, and even ransom payments in some policies — however, insurers increasingly require evidence of baseline security controls (MFA, EDR, backups) as a condition of coverage, recognizing that insurance complements rather than replaces actual security investment.",optionExplanations:["This is traditional property insurance, a different risk category.","Insurers require baseline controls as a condition of coverage, not a replacement for them.","Cyber insurance can cover forensics, notification, legal defense, and sometimes ransom.","This is an organizational policy, not an individual purchase requirement."]},
  {id:869,domain:A,question:"What is the purpose of implementing DNS filtering as a security control?",options:["Improving DNS resolution speed only","A backup mechanism for DNS outages","Blocking access to competitor websites","Blocking known malicious domains at resolution"],answer:3,explanation:"DNS filtering services (Cisco Umbrella, Cloudflare Gateway) maintain threat intelligence feeds of known malicious domains and block resolution requests to them — this provides an early, low-overhead layer of defense since malware often needs to resolve a C2 domain to communicate, and blocking that resolution can neutralize the threat before any actual malicious traffic is established.",optionExplanations:["Performance can be a side benefit, but the purpose is security blocking.","DNS filtering is an active control, not a failover mechanism.","Legitimate filtering targets malicious content, not competitors.","Blocking resolution to malicious domains can stop malware from reaching its C2 server."]},
  {id:870,domain:O,question:"What is the purpose of conducting a controlled phishing simulation campaign?",options:["Sending simulated emails to measure susceptibility","Publicly punishing employees who click","A one-time test conducted with no ongoing tracking or follow-up","Actually stealing real employee credentials"],answer:0,explanation:"Effective phishing simulation programs (using platforms like KnowBe4 or Proofpoint) track click rates over time, provide immediate just-in-time training for employees who click (rather than punitive action), and use results to identify patterns (e.g., a specific department needs additional training) — the goal is behavior change and awareness improvement, not punishment or credential theft.",optionExplanations:["Simulations track click rates and provide just-in-time training rather than punishment.","Best practice uses clicking as a learning moment, not punishment.","Effective programs run simulations regularly, not just once.","Simulations don't retain real credentials; results drive training instead."]},
  {id:871,domain:T,question:"What is a Bluetooth bluejacking attack?",options:["Physically disabling a Bluetooth chip","Sending unsolicited messages to nearby devices","A legitimate pairing notification system","A severe attack that fully takes over a Bluetooth device"],answer:1,explanation:"Bluejacking is relatively low-risk — typically just sending unsolicited contact cards or text messages to nearby discoverable devices — and is distinct from bluesnarfing (unauthorized data theft from a Bluetooth device) or bluebugging (gaining full unauthorized control), which are far more serious security threats.",optionExplanations:["Bluejacking doesn't damage hardware; it sends unsolicited messages.","Bluejacking is a low-risk nuisance, distinct from data theft or device takeover.","Bluejacking is unauthorized, not a built-in pairing feature.","This describes bluebugging, a far more serious attack than bluejacking."]},
  {id:872,domain:A,question:"What is the purpose of a software-defined perimeter (SDP) architecture?",options:["A backup perimeter for firewall outages","A perimeter defined purely by an organization's own physical building walls","Protection against physical intrusion only","Dynamically creating hidden, encrypted connections to resources"],answer:3,explanation:"SDP (sometimes called a 'black cloud' approach) verifies user identity and device posture before granting access, then creates a direct, encrypted micro-tunnel to only the specific authorized resource — unlike traditional perimeter security, unauthorized users can't even see that protected resources exist on the network (no open ports visible to port scanning), significantly reducing the attack surface.",optionExplanations:["SDP is a primary architecture, not a firewall failover.","SDP is a logical architecture, not physical building boundaries.","SDP addresses network access security, not physical intrusion.","SDP hides protected resources from unauthorized users, reducing the attack surface."]},
  {id:873,domain:O,question:"What is the purpose of implementing automated security orchestration playbooks for phishing response?",options:["Scheduling office entertainment events","Automated workflows handling common phishing response steps","Requiring full manual execution with no automation","A backup used only when SOAR is offline"],answer:1,explanation:"A SOAR phishing playbook might automatically pull the email's headers and attachments for analysis, check if any other users received the same email and auto-quarantine those copies, query EDR to see if any recipients clicked the link, and auto-create a ticket — reducing response time from potentially hours of manual work to minutes, and ensuring consistent handling regardless of which analyst (or shift) is working.",optionExplanations:["This is wordplay unrelated to music or entertainment.","Automated playbooks pull headers, quarantine copies, and check for clicks in minutes, not hours.","Automation is the defining value; full manual work defeats the purpose.","Playbooks are the primary automated workflow, not a fallback."]},
  {id:874,domain:T,question:"What is a watering hole attack's primary advantage for attackers compared to direct phishing?",options:["Guaranteed compromise of every visitor","Always faster than a phishing campaign","Requires virtually no technical skill or specialized resources","Compromises security-aware targets via a trusted site"],answer:3,explanation:"Watering hole attacks are particularly valuable against sophisticated targets (security researchers, government employees, defense contractors) who have strong security awareness and would likely recognize/report a direct phishing attempt — by compromising a trusted third-party site instead, attackers bypass the target's heightened suspicion of direct communications.",optionExplanations:["Success depends on browser vulnerability and timing; it's not guaranteed.","Watering holes require time-intensive reconnaissance, often slower than phishing.","Compromising a site and deploying exploits requires real technical skill.","A trusted third-party site bypasses a wary target's suspicion of direct phishing."]},
  {id:875,domain:G,question:"What is the purpose of implementing a 'defense in depth' security strategy?",options:["Minimizing the number of controls deployed","Relying on one single extremely strong security control","Layering multiple redundant security controls","Focusing only on perimeter firewall rules"],answer:2,explanation:"A defense-in-depth approach for a database might include network segmentation, a firewall, an IPS, strong authentication, encryption at rest, database activity monitoring, and regular access reviews — even if an attacker bypasses the firewall, they still face multiple additional obstacles, unlike a single-point-of-failure approach where one bypassed control means complete compromise.",optionExplanations:["Defense in depth typically requires more, not fewer, controls.","This describes the opposite; layering avoids a single point of failure.","If one layer fails, additional layers still protect the system.","Defense in depth spans the whole environment, not just the perimeter."]},
  {id:876,domain:O,question:"What is the purpose of measuring and tracking 'dwell time' as a security metric?",options:["Measuring average server response time for web applications","Time an attacker stays undetected in a network","Time tickets sit unresolved in a queue","How long employees stay at their desks"],answer:1,explanation:"Industry dwell time averages have decreased over recent years due to improved detection technology (EDR, better SIEM analytics) but can still range from days to many months for sophisticated attacks — every additional day of undetected dwell time generally correlates with increased opportunity for data exfiltration, lateral movement, and overall breach impact, making dwell time reduction a key security program objective.",optionExplanations:["Response time is an application performance metric, not dwell time.","Longer dwell time generally means more opportunity for exfiltration and lateral movement.","Ticket queue time is an operational metric, distinct from attacker presence.","This is an HR metric, unrelated to attacker detection."]},
  {id:877,domain:T,question:"What is a UDP flood attack?",options:["An authorized UDP stress test","A vulnerability specific to TCP only","Compressing UDP packet headers","Overwhelming a target with UDP packets to random ports"],answer:3,explanation:"Because UDP is connectionless (no handshake required like TCP), attackers can rapidly send massive volumes of spoofed UDP packets without needing to complete any negotiation — the target system's resource consumption checking each port and generating responses, combined with the connectionless nature making source verification difficult, makes UDP floods a common and effective volumetric DoS technique.",optionExplanations:["This is malicious, unauthorized traffic, not authorized testing.","UDP floods target UDP's connectionless nature specifically, unlike TCP-based attacks.","This is a DoS technique, unrelated to header compression.","UDP's lack of a handshake lets attackers flood ports without any negotiation."]},
  {id:878,domain:A,question:"What is the purpose of implementing just-in-time (JIT) access provisioning?",options:["Elevated access only during holidays","Granting access only for the needed time window","A backup access method used only during unplanned outages","Skipping security review to speed onboarding"],answer:1,explanation:"JIT access (implemented via PAM solutions like CyberArk or Azure PIM) significantly reduces the standing attack surface — instead of an admin having permanent domain admin rights that could be compromised at any time, they request elevated access for a specific task, it's granted temporarily (e.g., 2 hours) with approval and logging, then automatically revoked, minimizing the window during which those credentials pose risk if compromised.",optionExplanations:["JIT is about limiting duration generally, not tied to holidays.","Temporary elevation with auto-revocation minimizes the window credentials pose risk.","JIT is a standard privileged access practice, not just an emergency mechanism.","JIT means temporary elevation with approval, not skipping review."]},
  {id:879,domain:O,question:"What is the purpose of an incident response communication plan?",options:["A general marketing communication plan unrelated to incidents","Setting up new employee email accounts","Internal chat tool etiquette guidelines","Defining who to inform, what to share, and how"],answer:3,explanation:"Communication plans prevent costly mistakes during high-pressure incidents — like a well-meaning employee posting incident details on social media before legal/PR has prepared an official statement, or missing a regulatory breach notification deadline (e.g., GDPR's 72-hour requirement) due to unclear ownership of that responsibility.",optionExplanations:["IR communication plans are incident-focused, not general marketing.","Email provisioning is an IT task, unrelated to incident communication.","Communication plans cover all key stakeholders, not just chat conventions.","Clear plans prevent premature disclosures and missed regulatory notification deadlines."]},
  {id:880,domain:T,question:"What is a wireless jamming attack?",options:["Requires physical access to cabling","A legitimate coverage-mapping technique","Improving and boosting wireless signal strength for legitimate nearby users","Transmitting interference to disrupt wireless communication"],answer:3,explanation:"Jamming attacks flood the same frequency spectrum used by WiFi (2.4GHz/5GHz) or other wireless protocols with noise/interference, denying service to legitimate users — unlike most cyberattacks, jamming requires physical proximity to the target's RF range and specialized equipment, and is illegal in most jurisdictions under telecommunications regulations regardless of intent.",optionExplanations:["Jamming needs RF proximity, not access to physical cables.","Jamming is unauthorized disruption, not legitimate coverage testing.","Jamming denies service; it doesn't boost connectivity.","Flooding the shared spectrum with noise denies legitimate devices the ability to communicate."]},
  {id:881,domain:G,question:"What is the purpose of a security policy exception review board or governance committee?",options:["A board with no executive accountability","Approving employee vacation requests","Handling building maintenance requests","Reviewing and approving security policy exceptions"],answer:3,explanation:"Governance committees (often including representatives from security, legal, IT, and business units) provide checks and balances for significant risk decisions — preventing any single individual from unilaterally accepting major organizational risk, and ensuring decisions consider multiple perspectives (legal liability, business impact, technical feasibility) before approval.",optionExplanations:["Governance committees typically report to and are accountable to leadership.","This is an HR function, unrelated to security governance.","Security governance addresses policy and risk, not facilities.","Cross-functional review prevents any single person from unilaterally accepting major risk."]},
  {id:882,domain:O,question:"What is the purpose of conducting a forensic memory (RAM) capture during incident response?",options:["Freeing up disk space by capturing a system's memory","Preserving volatile RAM before it's lost at shutdown","Testing memory chips for defects","A routine daily backup procedure"],answer:1,explanation:"Memory is volatile — its contents are lost the moment a system powers off — making memory capture (using tools like FTK Imager or Volatility for analysis) critical for capturing evidence of fileless malware, active malicious processes, or decryption keys that would never be discoverable from a disk image alone, which is why proper IR procedure often calls for memory capture before any system shutdown.",optionExplanations:["Memory capture is for evidence preservation, not storage management.","RAM holds fileless malware and keys that vanish once a system powers off.","This is forensic evidence work, not hardware defect testing.","Memory capture is an as-needed forensic step, not a routine backup."]},
];
